/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements NotificationAdapter so it can be registered with NotificationService.
 *
 * Features:
 * - Template rendering: generates structured email HTML per notification type
 * - Recipient validation: validates email format before sending
 * - Configurable sender address and display name
 * - Pluggable transport: swap the transport function for real SMTP/API integration
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Sender email address shown in the "From" field. */
  fromAddress: string;
  /** Display name for the sender. */
  fromName: string;
}

const defaultEmailConfig: EmailConfig = {
  fromAddress: 'noreply@taskflow.example.com',
  fromName: 'TaskFlow Pro',
};

/**
 * A rendered email ready for delivery.
 */
export interface RenderedEmail {
  from: string;
  to: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport function signature — swap this to integrate with a real provider.
 * The default transport logs the email (no-op). Replace with SendGrid, SES, SMTP, etc.
 */
export type EmailTransport = (email: RenderedEmail) => Promise<void>;

/**
 * Default transport: no-op (for development / testing).
 */
const noopTransport: EmailTransport = async () => {};

// ---------- Email templates ----------

const EMAIL_TEMPLATES: Record<NotificationType, (payload: NotificationPayload) => { html: string; text: string }> = {
  order_confirmation(payload) {
    const orderId = payload.metadata['orderId'] ?? 'N/A';
    const html = [
      '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2c3e50;">Order Confirmation</h1>`,
      `<p>Hi,</p>`,
      `<p>Thank you for your order <strong>${orderId}</strong>.</p>`,
      `<div style="background: #f8f9fa; padding: 16px; border-radius: 4px;">`,
      `<p>${payload.body}</p>`,
      `</div>`,
      `<p style="color: #7f8c8d; font-size: 12px;">If you have questions, reply to this email.</p>`,
      '</div>',
    ].join('\n');
    const text = `Order Confirmation\n\n${payload.body}\n\nOrder ID: ${orderId}`;
    return { html, text };
  },

  order_status_update(payload) {
    const orderId = payload.metadata['orderId'] ?? 'N/A';
    const newStatus = payload.metadata['newStatus'] ?? 'unknown';
    const html = [
      '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2c3e50;">Order Update</h1>`,
      `<p>Your order <strong>${orderId}</strong> status is now: <strong>${newStatus}</strong>.</p>`,
      `<div style="background: #f8f9fa; padding: 16px; border-radius: 4px;">`,
      `<p>${payload.body}</p>`,
      `</div>`,
      '</div>',
    ].join('\n');
    const text = `Order Update\n\nOrder ${orderId} is now: ${newStatus}\n\n${payload.body}`;
    return { html, text };
  },

  welcome(payload) {
    const html = [
      '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2c3e50;">Welcome to TaskFlow Pro!</h1>`,
      `<p>${payload.body}</p>`,
      `<p>Get started by exploring your dashboard.</p>`,
      '</div>',
    ].join('\n');
    const text = `Welcome to TaskFlow Pro!\n\n${payload.body}`;
    return { html, text };
  },

  account_updated(payload) {
    const changes = payload.metadata['changes'] ?? '';
    const html = [
      '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">',
      `<h1 style="color: #2c3e50;">Account Updated</h1>`,
      `<p>${payload.body}</p>`,
      changes ? `<p><em>Changed: ${changes}</em></p>` : '',
      '</div>',
    ].join('\n');
    const text = `Account Updated\n\n${payload.body}`;
    return { html, text };
  },
};

// ---------- Validation ----------

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that a recipient string looks like a valid email address.
 */
export function isValidEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

// ---------- Adapter ----------

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private config: EmailConfig;
  private transport: EmailTransport;
  private sentEmails: Array<{ rendered: RenderedEmail; payload: NotificationPayload; timestamp: Date }> = [];

  constructor(config: EmailConfig = defaultEmailConfig, transport?: EmailTransport) {
    this.config = config;
    this.transport = transport ?? noopTransport;
  }

  /**
   * Render a NotificationPayload into a full RenderedEmail using the template system.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const templateFn = EMAIL_TEMPLATES[payload.type];
    const { html, text } = templateFn(payload);

    return {
      from: `${this.config.fromName} <${this.config.fromAddress}>`,
      to: payload.recipient,
      subject: payload.subject,
      html,
      text,
    };
  }

  /**
   * Validate and resolve the recipient address.
   * Returns the normalized email or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const normalized = recipient.trim().toLowerCase();
    if (!isValidEmail(normalized)) {
      throw new Error(`Invalid email address: ${recipient}`);
    }
    return normalized;
  }

  /**
   * Send a notification as an email.
   *
   * Flow: validate recipient → render template → deliver via transport → return result.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Validate recipient
      const resolvedRecipient = this.resolveRecipient(payload.recipient);
      const resolvedPayload = { ...payload, recipient: resolvedRecipient };

      this.logger.info(
        `Sending email to ${resolvedRecipient}: "${payload.subject}"`,
      );

      // 2. Render template
      const rendered = this.renderEmail(resolvedPayload);

      // 3. Deliver via transport
      await this.transport(rendered);

      // 4. Record for testing / auditing
      this.sentEmails.push({ rendered, payload: resolvedPayload, timestamp: new Date() });

      this.logger.info(
        `Email delivered to ${resolvedRecipient} (from: ${rendered.from})`,
      );

      return {
        success: true,
        channel: 'email',
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Email delivery failed for ${payload.recipient}: ${message}`);

      return {
        success: false,
        channel: 'email',
        error: message,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all emails sent through this adapter (for testing/debugging).
   */
  getSentEmails(): Array<{ rendered: RenderedEmail; payload: NotificationPayload; timestamp: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

