import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EmailAdapter, isValidEmail } from '../../src/adapters/email.adapter.js';
import type { EmailTransport } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date(),
    ...overrides,
  };
}

describe('isValidEmail', () => {
  it('should accept valid email addresses', () => {
    expect(isValidEmail('alice@example.com')).toBe(true);
    expect(isValidEmail('bob+tag@sub.domain.org')).toBe(true);
    expect(isValidEmail('user@company.co')).toBe(true);
  });

  it('should reject invalid email addresses', () => {
    expect(isValidEmail('')).toBe(false);
    expect(isValidEmail('not-an-email')).toBe(false);
    expect(isValidEmail('@missing-local.com')).toBe(false);
    expect(isValidEmail('missing@')).toBe(false);
    expect(isValidEmail('spaces in@email.com')).toBe(false);
  });
});

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: EmailTransport;

  beforeEach(() => {
    transport = vi.fn(async () => {});
    adapter = new EmailAdapter(
      { fromAddress: 'noreply@taskflow.example.com', fromName: 'TaskFlow Pro' },
      transport,
    );
  });

  describe('channel', () => {
    it('should report channel as email', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('resolveRecipient', () => {
    it('should normalize valid emails to lowercase', () => {
      expect(adapter.resolveRecipient('Alice@Example.COM')).toBe('alice@example.com');
    });

    it('should trim whitespace', () => {
      expect(adapter.resolveRecipient('  bob@example.com  ')).toBe('bob@example.com');
    });

    it('should throw for invalid emails', () => {
      expect(() => adapter.resolveRecipient('not-valid')).toThrow('Invalid email address');
    });
  });

  describe('renderEmail', () => {
    it('should render order_confirmation template with HTML and text', () => {
      const payload = makePayload({ type: 'order_confirmation' });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.from).toBe('TaskFlow Pro <noreply@taskflow.example.com>');
      expect(rendered.to).toBe('alice@example.com');
      expect(rendered.subject).toBe('Order Confirmation: order-1');
      expect(rendered.html).toContain('Order Confirmation');
      expect(rendered.html).toContain('order-1');
      expect(rendered.text).toContain('Order Confirmation');
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
      });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('Order Update');
      expect(rendered.html).toContain('confirmed');
      expect(rendered.text).toContain('confirmed');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        type: 'welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Alice, welcome to TaskFlow Pro. Your account has been created.',
        metadata: { userId: 'user-1' },
      });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('Welcome to TaskFlow Pro');
      expect(rendered.html).toContain('Hi Alice');
      expect(rendered.text).toContain('Welcome');
    });

    it('should render account_updated template', () => {
      const payload = makePayload({
        type: 'account_updated',
        subject: 'Account Updated',
        body: 'Your account has been updated. Changed fields: name, email.',
        metadata: { userId: 'user-1', changes: 'name,email' },
      });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('Account Updated');
      expect(rendered.html).toContain('name,email');
      expect(rendered.text).toContain('Account Updated');
    });
  });

  describe('send', () => {
    it('should return success for a valid email', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.error).toBeUndefined();
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('should call the transport with rendered email', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      expect(transport).toHaveBeenCalledOnce();
      const rendered = (transport as ReturnType<typeof vi.fn>).mock.calls[0]![0];
      expect(rendered.to).toBe('alice@example.com');
      expect(rendered.from).toContain('TaskFlow Pro');
      expect(rendered.html).toContain('Order Confirmation');
    });

    it('should record sent emails', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.payload.recipient).toBe('alice@example.com');
      expect(sent[0]!.rendered.html).toContain('Order Confirmation');
    });

    it('should return failure for invalid recipient', async () => {
      const payload = makePayload({ recipient: 'bad-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.channel).toBe('email');
      expect(result.error).toContain('Invalid email address');
    });

    it('should not call transport when recipient is invalid', async () => {
      const payload = makePayload({ recipient: 'bad-email' });
      await adapter.send(payload);

      expect(transport).not.toHaveBeenCalled();
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: EmailTransport = async () => {
        throw new Error('SMTP connection refused');
      };
      const failAdapter = new EmailAdapter(undefined, failingTransport);

      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should normalize recipient to lowercase', async () => {
      const payload = makePayload({ recipient: 'Alice@Example.COM' });
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent[0]!.payload.recipient).toBe('alice@example.com');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should start with no sent emails', () => {
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return a copy of the array', async () => {
      await adapter.send(makePayload());
      const first = adapter.getSentEmails();
      const second = adapter.getSentEmails();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });
  });

  describe('default config', () => {
    it('should use default config when none provided', async () => {
      const defaultAdapter = new EmailAdapter();
      const payload = makePayload();
      const rendered = defaultAdapter.renderEmail(payload);

      expect(rendered.from).toBe('TaskFlow Pro <noreply@taskflow.example.com>');
    });
  });

  describe('integration with NotificationService', () => {
    it('should work when wired into NotificationService via constructor', async () => {
      // This test verifies the adapter conforms to the NotificationAdapter interface
      const { EventBus } = await import('../../src/events/event-bus.js');
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );

      resetNotificationIdCounter();
      const eventBus = new EventBus();
      const emailAdapter = new EmailAdapter(undefined, transport);
      const service = new NotificationService(eventBus, [emailAdapter]);

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      // Notification service should have recorded the notification
      expect(service.getNotificationCount()).toBe(1);
      // Transport should have been called
      expect(transport).toHaveBeenCalledOnce();
      // Sent email should have rendered HTML
      const sent = emailAdapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.rendered.html).toContain('Welcome to TaskFlow Pro');
    });
  });
});

