+    id: 'notif-0001',
+    type: 'order_confirmation',
+    channel: 'email',
+    recipient: 'alice@example.com',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    priority: 'normal',
+    metadata: { orderId: 'order-1', userId: 'user-1' },
+    createdAt: new Date(),
+    ...overrides,
+  };
+}
+
+describe('isValidEmail', () => {
+  it('should accept valid email addresses', () => {
+    expect(isValidEmail('alice@example.com')).toBe(true);
+    expect(isValidEmail('bob+tag@sub.domain.org')).toBe(true);
+    expect(isValidEmail('user@company.co')).toBe(true);
+  });
+
+  it('should reject invalid email addresses', () => {
+    expect(isValidEmail('')).toBe(false);
+    expect(isValidEmail('not-an-email')).toBe(false);
+    expect(isValidEmail('@missing-local.com')).toBe(false);
+    expect(isValidEmail('missing@')).toBe(false);
+    expect(isValidEmail('spaces in@email.com')).toBe(false);
+  });
+});
+
